def normalize_features(df, columns):
    for col in columns:
        col_min = df[col].min()
        col_max = df[col].max()
        rng = col_max - col_min
        if rng == 0:
            df[col] = 0.0
        else:
            df[col] = (df[col] - col_min) / rng
    return df

def normalize_features(df, columns):
    for col in columns:
        df[col] = (df[col] - df[col].min()) / (df[col].max() - df[col].min())
    return df
